(function enableTabDragAndDrop(){const nav=document.querySelector('nav');if(!nav)return;let dragged=null;function save(){const tabs=Array.from(nav.querySelectorAll('.tab'));localStorage.setItem('tabOrder',JSON.stringify(tabs.map(t=>t.dataset.tab)))}function apply(){const saved=JSON.parse(localStorage.getItem('tabOrder'));if(!saved)return;const tabs=Array.from(nav.querySelectorAll('.tab'));const map={};tabs.forEach(t=>map[t.dataset.tab]=t);saved.forEach(k=>{if(map[k])nav.appendChild(map[k])})}if(document.readyState==='loading')document.addEventListener('DOMContentLoaded',apply);else apply();nav.addEventListener('dragstart',e=>{dragged=e.target.closest('.tab');if(dragged){e.dataTransfer.effectAllowed='move';e.dataTransfer.setData('text/plain','');dragged.style.opacity='0.5'}});nav.addEventListener('dragend',()=>{if(dragged){dragged.style.opacity='1';dragged=null}});nav.addEventListener('dragover',e=>e.preventDefault());nav.addEventListener('drop',e=>{e.preventDefault();const target=e.target.closest('.tab');if(!target||!dragged||target===dragged)return;const tabs=Array.from(nav.querySelectorAll('.tab'));if(tabs.indexOf(dragged)<tabs.indexOf(target))nav.insertBefore(dragged,target.nextSibling);else nav.insertBefore(dragged,target);save()});nav.addEventListener('touchstart',e=>{dragged=document.elementFromPoint(e.touches[0].clientX,e.touches[0].clientY)?.closest('.tab');if(dragged)dragged.style.opacity='0.5'},{passive:!0});nav.addEventListener('touchmove',e=>{if(!dragged)return;e.preventDefault();const target=document.elementFromPoint(e.touches[0].clientX,e.touches[0].clientY)?.closest('.tab');if(target&&target!==dragged){const tabs=Array.from(nav.querySelectorAll('.tab'));if(tabs.indexOf(dragged)<tabs.indexOf(target))nav.insertBefore(dragged,target.nextSibling);else nav.insertBefore(dragged,target)}},{passive:!1});nav.addEventListener('touchend',()=>{if(dragged){dragged.style.opacity='1';save();dragged=null}})})();
